(function(){'use strict';var form=document.getElementById('sleep-quiz-form');if(!form)return;var RESULT_KEY='efi_sleep_quiz_result_v2';var questions=[{id:'s1',text:'I get into bed at roughly the same time most nights.',positive:true,domain:'rhythm'},{id:'s2',text:'I wake up at roughly the same time most mornings.',positive:true,domain:'rhythm'},{id:'s3',text:'I lie awake for more than 30 minutes before falling asleep.',positive:false,domain:'latency'},{id:'s4',text:'I wake up during the night and have trouble getting back to sleep.',positive:false,domain:'latency'},{id:'s5',text:'I wake up feeling restored instead of depleted.',positive:true,domain:'recovery'},{id:'s6',text:'My caffeine timing does not interfere with sleep.',positive:true,domain:'habits'},{id:'s7',text:'Screen use in the final hour before bed is hard to control.',positive:false,domain:'habits'},{id:'s8',text:'Stress rumination keeps my brain spinning at bedtime.',positive:false,domain:'latency'},{id:'s9',text:'My room is dark enough, cool enough, and quiet enough for sleep.',positive:true,domain:'habits'},{id:'s10',text:'I need naps just to function through normal days.',positive:false,domain:'recovery'},{id:'s11',text:'I can keep a shutdown routine even on busy days.',positive:true,domain:'habits'},{id:'s12',text:'My sleep schedule shifts a lot between weekdays and weekends.',positive:false,domain:'rhythm'},{id:'s13',text:'I rely on revenge bedtime scrolling even when I am exhausted.',positive:false,domain:'habits'},{id:'s14',text:'Morning light exposure is part of my normal routine.',positive:true,domain:'rhythm'},{id:'s15',text:'Poor sleep clearly worsens my focus, memory, or emotional regulation.',positive:false,domain:'recovery'},{id:'s16',text:'I wake up multiple times because of discomfort, pain, or breathing issues.',positive:false,domain:'recovery'}];var domainLabels={rhythm:'Schedule rhythm',latency:'Falling and staying asleep',recovery:'Wake quality and recovery',habits:'Pre-sleep habits and environment'};var mapLabel=['Never','Rarely','Sometimes','Often'];var progressText=document.getElementById('sleep-progress-text');var progressFill=document.getElementById('sleep-progress-fill');var groups=document.getElementById('sleep-question-groups');var error=document.getElementById('sleep-quiz-error');var results=document.getElementById('sleep-results');var title=document.getElementById('sleep-result-title');var lede=document.getElementById('sleep-result-lede');var actions=document.getElementById('sleep-actions');var scoreLine=document.getElementById('sleep-result-score');var domainBars=document.getElementById('sleep-domain-bars');var totalQuestions=questions.length;function renderQuestions(){groups.innerHTML=questions.map(function(q,idx){var opts=[0,1,2,3].map(function(n){return'<label><input type="radio" name="'+q.id+'" value="'+n+'"> '+mapLabel[n]+'</label>';}).join('');return'<article class="card" style="margin-bottom:var(--space-md);"><p><strong>'+(idx+1)+'.</strong> '+q.text+'</p><div class="quiz-scale-row">'+opts+'</div></article>';}).join('');}
function readScores(){var perItem=[];var domains={};Object.keys(domainLabels).forEach(function(k){domains[k]={total:0,count:0};});var answered=0;var total=0;questions.forEach(function(q){var pick=form.querySelector('input[name="'+q.id+'"]:checked');if(!pick)return;answered+=1;var raw=Number(pick.value);var score=q.positive?raw:(3-raw);total+=score;perItem.push({id:q.id,domain:q.domain,score:score});domains[q.domain].total+=score;domains[q.domain].count+=1;});return{answered:answered,total:total,perItem:perItem,domains:domains};}
function updateProgress(){var state=readScores();progressText.textContent=state.answered+' of '+totalQuestions+' answered';progressFill.style.width=(state.answered/totalQuestions*100)+'%';}
function bandFor(total){if(total>=38){return{title:'Sleep likely supports your executive functioning',lede:'Your current rest pattern looks protective. Keep it steady and avoid over-correcting what already works.',actions:['Protect wake time first; bedtime consistency follows.','Keep a 30-minute wind-down as non-negotiable infrastructure.','Watch early signs of slide: later caffeine, doom-scrolling, skipped morning light.']};}
if(total>=27){return{title:'Sleep is probably part of the friction',lede:'Your score suggests sleep is not catastrophic, but it is likely reducing attention, emotional control, and task initiation on harder days.',actions:['Pick one anchor: fixed wake time or fixed digital cutoff.','Move caffeine cutoff 60–90 minutes earlier this week.','Use a two-step shutdown ritual: brain dump + low-light routine.']};}
return{title:'Sleep debt is likely amplifying your EF struggles',lede:'This pattern often feels like motivation failure but is usually a physiology load problem. Start with stabilization, not self-criticism.',actions:['Run a 7-day sleep triage: same wake time, earlier light, earlier caffeine cutoff.','Remove one high-friction bedtime trigger (phone in bed, late work, intense media).','If loud snoring, breathing pauses, pain, or insomnia persist, seek medical sleep evaluation.']};}
function buildDomainBreakdown(domains){return Object.keys(domains).map(function(key){var d=domains[key];var max=d.count*3;var pct=max?Math.round((d.total/max)*100):0;return{key:key,label:domainLabels[key],score:d.total,max:max,pct:pct};}).sort(function(a,b){return a.pct-b.pct;});}
function renderDomainBars(breakdown){if(!domainBars)return;domainBars.innerHTML=breakdown.map(function(d){var tone=d.pct>=70?'strong':(d.pct>=45?'mixed':'weak');return('<div class="sleep-domain-row sleep-domain-row--'+tone+'">'+'<div class="sleep-domain-row__head">'+'<span class="sleep-domain-row__label">'+d.label+'</span>'+'<span class="sleep-domain-row__score">'+d.score+' / '+d.max+' ('+d.pct+'%)</span>'+'</div>'+'<div class="sleep-domain-row__track"><div class="sleep-domain-row__fill" style="width:'+d.pct+'%;"></div></div>'+'</div>');}).join('');}
function persistResult(state,breakdown,band){try{localStorage.setItem(RESULT_KEY,JSON.stringify({generatedAt:new Date().toISOString(),total:state.total,max:totalQuestions*3,bandTitle:band.title,breakdown:breakdown}));}catch(e){}}
function renderResult(state){var band=bandFor(state.total);var breakdown=buildDomainBreakdown(state.domains);title.textContent=band.title;lede.textContent=band.lede;if(scoreLine){var max=totalQuestions*3;var weakest=breakdown[0];scoreLine.textContent='Overall: '+state.total+' / '+max+'. Weakest area: '+weakest.label+' ('+weakest.pct+'%).';}
renderDomainBars(breakdown);actions.innerHTML=band.actions.map(function(item){return'<li>'+item+'</li>';}).join('');results.hidden=false;results.scrollIntoView({behavior:'smooth',block:'start'});persistResult(state,breakdown,band);}
form.addEventListener('change',updateProgress);form.addEventListener('submit',function(event){event.preventDefault();var state=readScores();if(state.answered!==totalQuestions){error.hidden=false;return;}
error.hidden=true;renderResult(state);});document.getElementById('sleep-reset-btn').addEventListener('click',function(){form.reset();results.hidden=true;error.hidden=true;try{localStorage.removeItem(RESULT_KEY);}catch(e){}
updateProgress();});renderQuestions();updateProgress();})();